import{_ as a,H as l,f as t,i as r}from"./chunks/framework.CcwY6gWF.js";const c=JSON.parse('{"title":"NS_Replay 插件","description":"","frontmatter":{},"headers":[],"relativePath":"zh/plugins/ns-replay.md","filePath":"zh/plugins/ns-replay.md"}'),i={name:"zh/plugins/ns-replay.md"};function p(o,e,n,u,s,d){return l(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="ns-replay-插件" tabindex="-1">NS_Replay 插件 <a class="header-anchor" href="#ns-replay-插件" aria-label="Permalink to &quot;NS_Replay 插件&quot;">​</a></h1><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>NS_Replay 是一个功能完善的虚幻引擎回放系统，支持录制、文件管理、精确跳转和状态同步。</p><p><strong>主要特性：</strong></p><ul><li>实时录制游戏会话</li><li>完整的回放列表管理</li><li>精确的时间跳转功能</li><li>支持暂停/继续播放</li><li>可调节播放速度</li><li>支持回放文件删除</li></ul><p><strong>支持平台：</strong></p><ul><li>Windows (Win64)</li><li>Mac</li><li>iOS</li><li>Android</li><li>Linux</li></ul><p><strong>引擎版本要求：</strong> Unreal Engine 5.0.0+</p><h2 id="蓝图节点说明" tabindex="-1">蓝图节点说明 <a class="header-anchor" href="#蓝图节点说明" aria-label="Permalink to &quot;蓝图节点说明&quot;">​</a></h2><h3 id="开始录制-startrecording" tabindex="-1">开始录制(StartRecording) <a class="header-anchor" href="#开始录制-startrecording" aria-label="Permalink to &quot;开始录制(StartRecording)&quot;">​</a></h3><p>开始录制新的回放。</p><p>参数：</p><ul><li>ReplayName（字符串）- 回放文件的名称，留空则使用默认名称</li></ul><p>返回：</p><ul><li>ReturnValue（布尔值）- 是否成功开始录制</li></ul><h3 id="stoprecording" tabindex="-1">StopRecording <a class="header-anchor" href="#stoprecording" aria-label="Permalink to &quot;StopRecording&quot;">​</a></h3><p>停止当前正在进行的录制。</p><p>参数： 无</p><p>返回：</p><ul><li>ReturnValue（布尔值）- 是否成功停止录制</li></ul><h3 id="getreplaylist" tabindex="-1">GetReplayList <a class="header-anchor" href="#getreplaylist" aria-label="Permalink to &quot;GetReplayList&quot;">​</a></h3><p>获取所有已录制的回放列表。</p><p>参数：</p><ul><li>OutReplayList（FReplayInfo数组）- 输出的回放信息数组</li></ul><p>返回：</p><ul><li>ReturnValue（布尔值）- 是否成功获取列表</li></ul><h3 id="playreplay" tabindex="-1">PlayReplay <a class="header-anchor" href="#playreplay" aria-label="Permalink to &quot;PlayReplay&quot;">​</a></h3><p>播放指定的回放。</p><p>参数：</p><ul><li>ReplayName（字符串）- 要播放的回放名称</li></ul><p>返回：</p><ul><li>ReturnValue（布尔值）- 是否成功开始播放</li></ul><h3 id="getreplaytotalduration" tabindex="-1">GetReplayTotalDuration <a class="header-anchor" href="#getreplaytotalduration" aria-label="Permalink to &quot;GetReplayTotalDuration&quot;">​</a></h3><p>获取当前回放的总时长（秒）。</p><p>参数： 无</p><p>返回：</p><ul><li>ReturnValue（浮点型）- 回放总时长，若无活动回放则返回 0.0</li></ul><h3 id="seektotime" tabindex="-1">SeekToTime <a class="header-anchor" href="#seektotime" aria-label="Permalink to &quot;SeekToTime&quot;">​</a></h3><p>跳转到回放的指定时间点。</p><p>参数：</p><ul><li>TimeInSeconds（浮点型）- 目标时间（秒）</li></ul><p>返回：</p><ul><li>ReturnValue（布尔值）- 是否成功跳转</li></ul><h3 id="getcurrentdatetime" tabindex="-1">GetCurrentDateTime <a class="header-anchor" href="#getcurrentdatetime" aria-label="Permalink to &quot;GetCurrentDateTime&quot;">​</a></h3><p>获取当前系统日期时间，格式为 &quot;YYYY-MM-DD HH-MM&quot;。</p><p>参数： 无</p><p>返回：</p><ul><li>ReturnValue（字符串）- 格式化的日期时间字符串</li></ul><h3 id="getcurrentreplaytime" tabindex="-1">GetCurrentReplayTime <a class="header-anchor" href="#getcurrentreplaytime" aria-label="Permalink to &quot;GetCurrentReplayTime&quot;">​</a></h3><p>获取当前回放的播放进度时间（秒）。</p><p>参数： 无</p><p>返回：</p><ul><li>ReturnValue（浮点型）- 当前播放时间，若无活动回放则返回 0.0</li></ul><h3 id="pausereplay" tabindex="-1">PauseReplay <a class="header-anchor" href="#pausereplay" aria-label="Permalink to &quot;PauseReplay&quot;">​</a></h3><p>暂停回放播放。</p><p>参数： 无</p><p>返回：</p><ul><li>ReturnValue（布尔值）- 是否成功暂停</li></ul><h3 id="resumereplay" tabindex="-1">ResumeReplay <a class="header-anchor" href="#resumereplay" aria-label="Permalink to &quot;ResumeReplay&quot;">​</a></h3><p>恢复回放播放。</p><p>参数： 无</p><p>返回：</p><ul><li>ReturnValue（布尔值）- 是否成功恢复</li></ul><h3 id="setreplayplaybackspeed" tabindex="-1">SetReplayPlaybackSpeed <a class="header-anchor" href="#setreplayplaybackspeed" aria-label="Permalink to &quot;SetReplayPlaybackSpeed&quot;">​</a></h3><p>设置回放播放速度。</p><p>参数：</p><ul><li>PlaybackSpeed（浮点型）- 播放速度，范围 0.1 - 10.0，1.0 为正常速度</li></ul><p>返回：</p><ul><li>ReturnValue（布尔值）- 是否成功设置速度</li></ul><h3 id="deletereplay" tabindex="-1">DeleteReplay <a class="header-anchor" href="#deletereplay" aria-label="Permalink to &quot;DeleteReplay&quot;">​</a></h3><p>删除指定的回放文件。</p><p>参数：</p><ul><li>ReplayName（字符串）- 要删除的回放名称</li></ul><p>返回：</p><ul><li>ReturnValue（布尔值）- 是否成功删除</li></ul><h3 id="isworldinreplay" tabindex="-1">IsWorldInReplay <a class="header-anchor" href="#isworldinreplay" aria-label="Permalink to &quot;IsWorldInReplay&quot;">​</a></h3><p>检查当前世界是否正在回放模式中。</p><p>参数： 无</p><p>返回：</p><ul><li>ReturnValue（布尔值）- 是否在回放模式中</li></ul><h2 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to &quot;注意事项&quot;">​</a></h2><ol><li><strong>文件存储位置</strong> - 回放文件默认存储在 <code>[项目目录]/Saved/Demos/</code> 文件夹中</li><li><strong>名称生成</strong> - 如果未指定回放名称，会自动生成格式为 <code>Replay_YYYYMMDD_HHMMSS</code> 的名称</li><li><strong>速度限制</strong> - 播放速度限制在 0.1x 到 10x 之间</li><li><strong>对象复制</strong> - 确保需要录制的Actor设置了正确的复制属性</li><li><strong>网络模式</strong> - 回放系统在单机和网络模式下都可使用</li></ol><h2 id="技术支持" tabindex="-1">技术支持 <a class="header-anchor" href="#技术支持" aria-label="Permalink to &quot;技术支持&quot;">​</a></h2><ul><li>插件作者：NodeSmith</li><li>官方文档：<a href="https://dztz.github.io/NS_Document/Replay/indexEn.html" target="_blank" rel="noreferrer">https://dztz.github.io/NS_Document/Replay/indexEn.html</a></li><li>Fab商店：com.epicgames.launcher://ue/Fab/product79aa810c-f7a0-4582-b257-287d7f42aefe</li></ul>',84)])])}const y=a(i,[["render",p]]);export{c as __pageData,y as default};
